import requests

response = requests.post(
    'https://api.pinelabs.com/v1/customers',
    headers={
        'Content-Type': 'application/json',
        'Authorization': 'Bearer YOUR_API_KEY'
    },
    json={
        'first_name': 'John',
        'last_name': 'Doe',
        'email_id': 'john@example.com',
        'mobile_number': '919876543210'
    }
)
print(response.json())
